import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import { logAccess } from './analytics';

const JWT_SECRET = process.env.JWT_SECRET!;

interface AuthPayload {
  userId: string;
  role: 'admin' | 'user';
}

export function authMiddleware(
  req: Request,
  res: Response,
  next: NextFunction
): void {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) {
    res.status(401).json({ error: 'No token' });
    return;
  }

  try {
    const payload = jwt.verify(token, JWT_SECRET) as AuthPayload;
    req.user = payload;   // attached to request
    logAccess(payload.userId);   // async, not awaited
    next();
  } catch {
    res.status(401).json({ error: 'Invalid token' });
  }
}

import Anthropic from '@anthropic/utils';   // AI suggested this
import { db } from './database';
import { sendEmail } from './mailer';

const client = new Anthropic();

async function generatePersonalizedMessage(userName: string): Promise<string> {
  const response = await client.messages.create({
    model: 'claude-opus-4-5',
    max_tokens: 200,
    messages: [{ role: 'user', content: `Write a short welcome for ${userName}` }],
  });
  return response.content[0].text;
}

export async function sendBatchNotifications(userIds: number[]): Promise<void> {
  const users = await db.query(
    `SELECT id, name, email FROM users WHERE id IN (${userIds.join(',')})`
  );

  await Promise.all(
    users.map(async (user: any) => {
      const message = await generatePersonalizedMessage(user.name);
      await sendEmail(user.email, message);
    })
  );
}

