export async function DELETE(req: Request) {
  const body = await req.json();
  const datasetId = body.datasetId;

  await db.datasets.delete({ where: { id: datasetId } });

  logAuditEvent({
    userId: body.userId,
    action: 'DELETE_DATASET',
    metadata: { datasetId },
  });

  return new Response(JSON.stringify({ success: true }), { status: 200 });
}

// lib/config-loader.ts

interface ModelConfig {
  tenantId: number;   // from a Snowflake / warehouse row — can exceed 2^53
  modelName: string;
  maxTokens: number;
  allowedFeatures: string[];
}

let cachedConfig: ModelConfig | null = null;

export function loadConfig(rawJson: string): ModelConfig {
  const config = JSON.parse(rawJson) as ModelConfig;
  cachedConfig = config;
  return config;
}

export function getMaxTokens(): number {
  return cachedConfig!.maxTokens;
}

export function isFeatureAllowed(feature: string): boolean {
  return cachedConfig!.allowedFeatures.includes(feature);
}

