import { db } from '@/lib/db';

type RunStatus = 'pending' | 'running' | 'success' | 'failed';

interface Dataset {
  id: number;
  name: string;
  ownerId: number;
}

interface EnrichedDataset extends Dataset {
  latestRunStatus: RunStatus;
}

export async function GET(req: Request) {
  const { searchParams } = new URL(req.url);
  const ownerId = parseInt(searchParams.get('ownerId')!);

  const datasets: Dataset[] = await db.query(
    'SELECT id, name, owner_id FROM datasets WHERE owner_id = $1',
    [ownerId]
  );

  // Enrich each dataset with the latest pipeline run
  const enriched = await Promise.all(
    datasets.map(async (ds) => {
      const runs = await db.query(
        'SELECT status FROM pipeline_runs WHERE dataset_id = $1 ORDER BY created_at DESC LIMIT 1',
        [ds.id]
      );
      const latestRunStatus = (runs[0]?.status ?? 'pending') as RunStatus;
      return { ...ds, latestRunStatus };
    })
  );

  return Response.json(enriched);
}

