import { validateRecord } from './validator';
import { enrichRecord } from './enricher';
import { warehouseClient } from './warehouse';

interface RawRecord {
  id: string;
  payload: unknown;
}

interface ProcessedRecord {
  id: string;
  enrichedPayload: object;
  validatedAt: Date;
}

async function processOne(record: RawRecord): Promise<ProcessedRecord> {
  await validateRecord(record);          // throws on invalid
  const enriched = await enrichRecord(record);
  return {
    id: record.id,
    enrichedPayload: enriched,
    validatedAt: new Date(),
  };
}

export async function runPipeline(records: RawRecord[]): Promise<void> {
  const processed: ProcessedRecord[] = [];

  for (const record of records) {
    const result = await processOne(record);  // sequential — one at a time
    processed.push(result);
  }

  // Write all processed records to the warehouse in one batch
  await warehouseClient.batchInsert(processed);

  // Notify downstream consumers
  records.forEach(r => {
    warehouseClient.publishEvent('record.processed', { id: r.id });  // floating promise
  });
}
